public void testSetterFunctionNotReduced() {
  checkCompilesToSame(
      "var obj = {\n" +
      "  set prop(val) { this._prop = val; }\n" +
      "};", 1);
}

public void testMixedGetterSetterNotReduced() {
  checkCompilesToSame(
      "var obj = {\n" +
      "  get prop() { return this._prop; },\n" +
      "  set prop(val) { this._prop = val; }\n" +
      "};", 1);
}

public void testRegularFunctionExpressionReduced() {
  test(
      "var f = function() { return 1; }; f(); f(); f(); f(); f(); f();",
      "var f = function $jscomp$1() { return 1; }; $jscomp$1(); $jscomp$1(); $jscomp$1(); $jscomp$1(); $jscomp$1(); $jscomp$1();", 1);
}
